	usagestatsReaderRole = RoleDTO{
		Name:        "fixed:usagestats:reader",
		DisplayName: "Usage report reader",
		Description: "View usage statistics report",
		Group:       "Statistics",
		Permissions: []Permission{
			{Action: ActionUsageStatsRead},
		},
	}
